def predict(triples: list[Triple]) -> str:
    if not triples:
        return ""

    # Group triples by subject
    subject_triples = {}
    for triple in triples:
        if triple.subject not in subject_triples:
            subject_triples[triple.subject] = []
        subject_triples[triple.subject].append(triple)

    # Get the main subject (first subject found)
    main_subject = list(subject_triples.keys())[0]
    main_triples = subject_triples[main_subject]

    # Categorize predicates
    personal_info = ['birthDate', 'birthPlace', 'birthName', 'nationality', 'deathDate', 'deathPlace', 'alternativeName']
    career_info = ['occupation', 'status', 'almaMater', 'awards', 'award', 'ribbonAward', 'title', 'servedAsChiefOfTheAstronautOfficeIn']
    nasa_info = ['selectedByNasa', 'mission', 'timeInSpace']
    mission_info = ['operator', 'commander', 'backupPilot', 'crewMembers', 'cosparId']

    sentence_parts = []

    # Build personal info sentence
    personal_parts = []
    for triple in main_triples:
        if triple.predicate in personal_info:
            if triple.predicate == 'birthDate':
                personal_parts.append(f"born on {triple.object}")
            elif triple.predicate == 'birthPlace':
                personal_parts.append(f"born in {triple.object}")
            elif triple.predicate == 'birthName':
                personal_parts.append(f"whose birth name was {triple.object}")
            elif triple.predicate == 'nationality':
                personal_parts.append(f"of {triple.object} nationality")
            elif triple.predicate == 'deathDate':
                personal_parts.append(f"who passed away on {triple.object}")
            elif triple.predicate == 'deathPlace':
                personal_parts.append(f"who died in {triple.object}")
            elif triple.predicate == 'alternativeName':
                personal_parts.append(f"also known as {triple.object}")

    if personal_parts:
        sentence_parts.append(f"{main_subject}, {' '.join(personal_parts)}")
    else:
        sentence_parts.append(main_subject)

    # Build career info
    career_parts = []
    for triple in main_triples:
        if triple.predicate in career_info:
            if triple.predicate == 'occupation':
                career_parts.append(f"worked as a {triple.object}")
            elif triple.predicate == 'status':
                career_parts.append(f"currently {triple.object}")
            elif triple.predicate == 'almaMater':
                career_parts.append(f"educated at {triple.object}")
            elif triple.predicate == 'awards':
                career_parts.append(f"received {triple.object} awards")
            elif triple.predicate == 'award':
                career_parts.append(f"received the {triple.object}")
            elif triple.predicate == 'title':
                career_parts.append(f"held the title of {triple.object}")

    if career_parts:
        sentence_parts.append(f"who {' and '.join(career_parts)}")

    # Build NASA info
    nasa_parts = []
    for triple in main_triples:
        if triple.predicate in nasa_info:
            if triple.predicate == 'selectedByNasa':
                nasa_parts.append(f"selected by NASA in {triple.object}")
            elif triple.predicate == 'mission':
                nasa_parts.append(f"participated in {triple.object}")
            elif triple.predicate == 'timeInSpace':
                minutes = float(triple.object.replace('"', '').replace('(', '').replace(')', '').split('"')[0])
                hours = minutes / 60
                nasa_parts.append(f"with {hours:.1f} hours in space")

    if nasa_parts:
        sentence_parts.append(f"and {' '.join(nasa_parts)}")

    # Build mission info (for mission-related subjects)
    mission_parts = []
    for triple in main_triples:
        if triple.predicate in mission_info:
            if triple.predicate == 'operator':
                mission_parts.append(f"operated by {triple.object}")
            elif triple.predicate == 'commander':
                mission_parts.append(f"commanded by {triple.object}")
            elif triple.predicate == 'backupPilot':
                mission_parts.append(f"with {triple.object} as backup pilot")
            elif triple.predicate == 'crewMembers':
                mission_parts.append(f"crew member {triple.object}")
            elif triple.predicate == 'cosparId':
                mission_parts.append(f"with COSPAR ID {triple.object}")

    if mission_parts:
        sentence_parts.append(f", {' '.join(mission_parts)}")

    # Combine all parts
    result = ", ".join(sentence_parts)
    if result and not result.endswith('.'):
        result += "."

    return result

# EVOLVE-BLOCK-END

